20	const basePremiumForItem = (item: Item): number =>
21	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
22	
23	const isNewcomer = (customer: Customer): boolean =>
24	  customer.yearsWithMHPCO === 0;
25	
26	const premiumForItem = (item: Item, customer: Customer): number => {
27	  const base = basePremiumForItem(item);
28	  const newcomerSurcharge = isNewcomer(customer) ? base * NEWCOMER_PER_ITEM_SURCHARGE_RATE : 0;
29	  return base + newcomerSurcharge;
30	};
31	
32	export const quote = (input: QuoteInput): { premium: number } => {
33	  const itemsTotal = input.items.reduce(
34	    (sum, item) => sum + premiumForItem(item, input.customer),
35	    0,
36	  );
37	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
38	};
39	
40	export const claim = (_input: unknown): unknown => {
41	  return undefined;
42	};
